<?php
 namespace League\CommonMark; class CommonMarkConverter extends MarkdownConverter { public const VERSION = '1.6-dev'; public function __construct(array $config = [], EnvironmentInterface $environment = null) { if ($environment === null) { $environment = Environment::createCommonMarkEnvironment(); } else { @\trigger_error(\sprintf('Passing an $environment into the "%s" constructor is deprecated in 1.6 and will not be supported in 2.0; use MarkdownConverter instead. See https://commonmark.thephpleague.com/2.0/upgrading/consumers/#commonmarkconverter-and-githubflavoredmarkdownconverter-constructors for more details.', self::class), \E_USER_DEPRECATED); } if ($environment instanceof ConfigurableEnvironmentInterface) { $environment->mergeConfig($config); } parent::__construct($environment); } } 